trait KeyManagementService {
  def getKey(keyId: String): Option[SecretKey]
  def storeKey(keyId: String, key: SecretKey): Unit
}

class InMemoryKeyManagementService extends KeyManagementService {
  private val keyStore = scala.collection.concurrent.TrieMap[String, SecretKey]()
  
  def getKey(keyId: String): Option[SecretKey] = keyStore.get(keyId)
  
  def storeKey(keyId: String, key: SecretKey): Unit = {
    keyStore.put(keyId, key)
  }
}

case class SessionToken(
